import json, glob, os
# Find latest session dir
sessions = sorted(glob.glob('.yoyo/state/sessions/*'), reverse=True)
if sessions:
    s = sessions[0]
    claims_f = os.path.join(s, 'claims.json')
    if os.path.exists(claims_f):
        claims = json.load(open(claims_f))
        print('claims.json keys:', list(claims.keys())[:20])
        if 'unresolved_families' in claims:
            print('unresolved_families:', claims['unresolved_families'][:5])
    states_f = os.path.join(s, 'states.json')
    if os.path.exists(states_f):
        states = json.load(open(states_f))
        print('states.json keys:', list(states.keys())[:20])
        if 'task_states' in states:
            for k, v in states.get('task_states', {}).items():
                print(f'  task_state {k}: {v}')
else:
    print('No session dirs found')
" 2>&1

